def solve(*args):
    if not args:
        return None

    # Assuming args should contain a list of items to process
    processed_items = []
    for item in args:
        if isinstance(item, str) and item.strip():
            processed_items.append(item.strip())
        else:
            return None  # Invalid input

    # Example core logic: return the count of valid items
    return len(processed_items)
